    const { function_slug, before } = payload;
    const projectRef = Deno.env.get("SUPABASE_URL")?.split("https://")[1].split(".")[0];
    const cloudKey = Deno.env.get("CONDUIT_ACCESS_TOKEN");

    if (!projectRef || !cloudKey) throw new Error("Missing ProjectRef or CONDUIT_ACCESS_TOKEN");

    // Handle Timestamps: Use provided 'before' (ms) or default to now
    const endDate = before ? new Date(parseInt(before)) : new Date();
    const startDate = new Date(endDate.getTime() - (24 * 60 * 60 * 1000)); // 24h window

    const isoStart = startDate.toISOString();
    const isoEnd = endDate.toISOString();

    // Query to filter by function slug within the Analytics platform
    const sql = `SELECT 
                    timestamp, 
                    event_message, 
                    TO_JSON_STRING(metadata) as metadata_json
                 FROM function_logs
                 WHERE (event_message LIKE '%${function_slug}%' OR TO_JSON_STRING(metadata) LIKE '%${function_slug}%')
                 ORDER BY timestamp DESC 
                 LIMIT 50`;

