win.closeMironWidget = () => {
    const existingWidget = doc.querySelector('.in-book-widget');
    if (existingWidget) {
        const page = existingWidget.closest('.page') || doc.body;
        existingWidget.classList.remove('active');

        const shiftedEls = page.querySelectorAll('.shifted-down');
        shiftedEls.forEach(el => {
            el.classList.remove('shifted-down');
            el.style.transform = '';
        });

        setTimeout(() => {
            if (existingWidget.parentNode) existingWidget.parentNode.removeChild(existingWidget);
            if (page.dataset.originalHeight) {
                page.style.height = page.dataset.originalHeight + 'px';
            }
            page.dataset.hasSplit = "false";
            if (win.updateParentDims) win.updateParentDims();
        }, 400);
    }
};

win.insertMironWidget = () => {
    if (!win.lastHighlightedRange) return false;

    if (doc.querySelector('.in-book-widget')) {
        // Immediately tear down old one to prevent glitching
        const oldWidget = doc.querySelector('.in-book-widget');
        const oldPage = oldWidget.closest('.page') || doc.body;
        oldWidget.remove();
        oldPage.querySelectorAll('.shifted-down').forEach(el => {
            el.classList.remove('shifted-down');
            el.style.transform = '';
        });
        if (oldPage.dataset.originalHeight) oldPage.style.height = oldPage.dataset.originalHeight + 'px';
    }

    const range = win.lastHighlightedRange;
    const startNode = range.startContainer;
    let page = startNode.parentElement.closest('.page');
    if (!page) page = doc.body;

    const textContainer = page.querySelector('.text-container') || page;
    const GAP_HEIGHT = 320; 
    const pageRect = page.getBoundingClientRect();
    const rangeRect = range.getBoundingClientRect();

    // Local Y coordinate of the highlighted text
    const highlightBottom = rangeRect.bottom - pageRect.top;

    // Map all elements for Spatial Gap Detection
    const els = Array.from(textContainer.querySelectorAll('span, p, img, .q-text, .q-media-content'));
    let elementsData = [];

    els.forEach(el => {
        if (el.classList.contains('in-book-widget')) return;
        const rect = el.getBoundingClientRect();
        if (rect.width > 0 && rect.height > 0) {
            elementsData.push({
                el: el,
                top: rect.top - pageRect.top,
                bottom: rect.bottom - pageRect.top,
                center: (rect.top + rect.bottom) / 2 - pageRect.top
            });
        }
    });

    // Find elements physically below the highlight
    let belowEls = elementsData.filter(d => d.top >= highlightBottom - 5);
    belowEls.sort((a, b) => a.top - b.top);

    // PARAGRAPH GAP DETECTION ALGORITHM
    let splitY = highlightBottom + 10; 
    if (belowEls.length > 0) {
        let currentBottom = belowEls[0].bottom;
        for (let i = 1; i < Math.min(belowEls.length, 50); i++) {
            const nextEl = belowEls[i];
            // If gap between this line and next line is > 12px, it's a paragraph break
            if (nextEl.top - currentBottom > 12) {
                splitY = currentBottom + ((nextEl.top - currentBottom) / 2);
                break;
            }
            currentBottom = Math.max(currentBottom, nextEl.bottom);
        }
    }

    if (!page.dataset.originalHeight) {
        page.dataset.originalHeight = pageRect.height;
    }

    page.style.height = (parseFloat(page.dataset.originalHeight) + GAP_HEIGHT) + "px";

